import{_ as o,o as i,c as a,a2 as l}from"./chunks/framework.BZO4qERu.js";const h=JSON.parse('{"title":"排障指南","description":"","frontmatter":{},"headers":[],"relativePath":"guide/troubleshooting.md","filePath":"guide/troubleshooting.md","lastUpdated":1780478520000}'),t={name:"guide/troubleshooting.md"};function d(s,e,r,n,c,p){return i(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="排障指南" tabindex="-1">排障指南 <a class="header-anchor" href="#排障指南" aria-label="Permalink to &quot;排障指南&quot;">​</a></h1><h2 id="桥接服务无法启动" tabindex="-1">桥接服务无法启动 <a class="header-anchor" href="#桥接服务无法启动" aria-label="Permalink to &quot;桥接服务无法启动&quot;">​</a></h2><p><strong>现象</strong>：从本地工作台启动 bridge 失败，或者 daemon 启动后立即退出。</p><p><strong>排查步骤</strong>：</p><ol><li>运行本地 doctor 脚本，或查看工作台日志定位问题。</li><li>确认已安装 Node.js &gt;= 20：<code>node --version</code>。</li><li>确认 Codex CLI 可用：<code>codex --version</code>。</li><li>确认配置文件存在：<code>ls -la ~/.codex-to-im/config.env</code>。</li><li>查看 <code>~/.codex-to-im/logs/</code> 下的启动错误日志。</li></ol><p><strong>常见原因</strong>：</p><ul><li><code>config.env</code> 缺失或内容无效。打开本地工作台并保存一份有效配置。</li><li>Node.js 未安装或版本不正确。安装 Node.js &gt;= 20。</li><li>端口或资源冲突。检查是否已有另一个 bridge 实例正在运行。</li></ul><h2 id="收不到消息" tabindex="-1">收不到消息 <a class="header-anchor" href="#收不到消息" aria-label="Permalink to &quot;收不到消息&quot;">​</a></h2><p><strong>现象</strong>：bot 在线，但不会回复消息。</p><p><strong>排查步骤</strong>：</p><ol><li>使用本地工作台测试工具或 doctor 脚本验证通道凭据。</li><li>检查配置中的 allowed user IDs。如果已设置，只有列表中的用户可以交互。</li><li>飞书：确认应用版本已审批通过，并且事件订阅已配置。</li><li>查看 <code>~/.codex-to-im/logs/</code> 中最近是否有 incoming message 事件。</li></ol><h2 id="飞书流式卡片不可用" tabindex="-1">飞书流式卡片不可用 <a class="header-anchor" href="#飞书流式卡片不可用" aria-label="Permalink to &quot;飞书流式卡片不可用&quot;">​</a></h2><p><strong>现象</strong>：飞书只收到最终普通消息，或者已经勾选 <code>Enable Feishu streaming response cards</code> 但流式卡片没有出现。</p><p><strong>排查步骤</strong>：</p><ol><li>查看 <code>~/.codex-to-im/logs/bridge.log</code>。</li><li>搜索飞书错误 <code>99991672</code>。</li><li>如果错误中提到 <code>cardkit:card:write</code>，补充并发布缺失的飞书权限： <ul><li><code>cardkit:card:write</code></li><li><code>cardkit:card:read</code></li><li><code>im:message:update</code></li></ul></li><li>飞书应用新版本审批通过后，重启 bridge。</li></ol><p><strong>重要行为说明</strong>：</p><ul><li>如果卡片创建被拒绝，bridge 会降级发送普通最终结果消息。</li><li>即使飞书权限正确，当前 <code>codex</code> runtime 通常也会在 turn 完成时一次性给出 assistant 文本，而不是逐 token 输出。</li><li>因此飞书流式卡片目前更适合展示 <code>Thinking</code> / 工具进度更新；最终回复文本仍可能一次性出现。</li></ul><h2 id="权限审批超时" tabindex="-1">权限审批超时 <a class="header-anchor" href="#权限审批超时" aria-label="Permalink to &quot;权限审批超时&quot;">​</a></h2><p><strong>现象</strong>：Codex 会话已经开始，但等待工具审批时超时。</p><p><strong>排查步骤</strong>：</p><ol><li>bridge 通过 SDK/CLI 运行 Codex；确认当前 sandbox 和 approval policy 与任务预期匹配。</li><li>使用 IM 中的权限提示审批工具请求；如果希望无人值守执行，请调整 Codex 审批设置。</li><li>如果超时发生在 API 调用期间，检查网络连通性。</li></ol><h2 id="内存占用过高" tabindex="-1">内存占用过高 <a class="header-anchor" href="#内存占用过高" aria-label="Permalink to &quot;内存占用过高&quot;">​</a></h2><p><strong>现象</strong>：daemon 进程内存持续增长。</p><p><strong>排查步骤</strong>：</p><ol><li>从本地工作台查看当前 bridge 状态。</li><li>重启 daemon 释放内存：<div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>先在本地工作台停止 bridge，再重新启动。</span></span></code></pre></div></li><li>如果问题持续存在，检查当前活跃会话数量。每个 Codex 会话都会占用内存。</li><li>查看日志中是否存在可能导致内存泄漏的错误循环。</li></ol><h2 id="过期-pid-文件" tabindex="-1">过期 PID 文件 <a class="header-anchor" href="#过期-pid-文件" aria-label="Permalink to &quot;过期 PID 文件&quot;">​</a></h2><p><strong>现象</strong>：状态显示为 running，但进程不存在；或者启动被拒绝，因为系统误以为 daemon 已经运行。</p><p>daemon 管理脚本（<code>daemon.sh</code>）会自动处理过期 PID 文件。如果仍然遇到问题：</p><ol><li>从本地工作台停止 bridge。这通常会清理过期 PID 文件。</li><li>如果停止也失败，手动删除 PID 文件：<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.codex-to-im/runtime/bridge.pid</span></span></code></pre></div></li><li>再次从本地工作台启动 bridge。</li></ol>',29)])])}const u=o(t,[["render",d]]);export{h as __pageData,u as default};
